noncompliant:
// Noncompliant: Same variable on both sides of comparison
void checkValue(int a, int b) {
    if (a == a) { // Always true
        printf("This is redundant");
    }

    if (b != b) { // Always false
        printf("This will never execute");
    }
}

compliant:
// Compliant: Different variables in comparison
void checkValue(int a, int b) {
    if (a == b) { // Meaningful comparison
        printf("Values are equal");
    }

    if (a != b) { // Meaningful comparison
        printf("Values are different");
    }
}
